typedef unsigned long ulong;
typedef unsigned char uchar;

/*
 * QEMU loongarch64 virt exposes a 16550-compatible UART at this LS7A address.
 * This remains a staged bring-up probe before the full LoongArch port.
 */
#define UART0_BASE 0x1fe001e0UL
#define UART_THR   0
#define UART_LSR   5
#define UART_LSR_THRE 0x20

#define SYSCON_BASE 0x100e001cUL
#define SYSCON_POWEROFF 0x34

#define CSR_CRMD   0x0
#define CSR_PRMD   0x1
#define CSR_ECFG   0x4
#define CSR_ESTAT  0x5
#define CSR_ERA    0x6
#define CSR_EENTRY 0xc

#define LA_ECODE_SYS 0xbUL
#define LA_SYS_WRITE 64UL
#define LA_SYS_EXIT  93UL

enum {
  TF_A0 = 2,
  TF_A1 = 3,
  TF_A2 = 4,
  TF_A7 = 9,
};

extern void la_exception_entry(void);
extern void la_enter_user_probe(void (*entry)(void), ulong sp);
extern void la_user_probe(void);
extern void la_after_user_probe(void);

static uchar user_stack[4096] __attribute__((aligned(16)));

static inline void
mmio_write8(ulong addr, uchar value)
{
  *(volatile uchar *)addr = value;
}

static inline uchar
mmio_read8(ulong addr)
{
  return *(volatile uchar *)addr;
}

static inline void
csr_write_ecfg(ulong value)
{
  asm volatile("csrwr %0, 0x4" : "+r"(value) :: "memory");
}

static inline void
csr_write_prmd(ulong value)
{
  asm volatile("csrwr %0, 0x1" : "+r"(value) :: "memory");
}

static inline void
csr_write_eentry(ulong value)
{
  asm volatile("csrwr %0, 0xc" : "+r"(value) :: "memory");
}

static inline ulong
csr_read(ulong csr)
{
  ulong value = 0;

  switch(csr){
  case CSR_CRMD:
    asm volatile("csrrd %0, 0x0" : "=r"(value));
    break;
  case CSR_PRMD:
    asm volatile("csrrd %0, 0x1" : "=r"(value));
    break;
  case CSR_ESTAT:
    asm volatile("csrrd %0, 0x5" : "=r"(value));
    break;
  case CSR_ERA:
    asm volatile("csrrd %0, 0x6" : "=r"(value));
    break;
  default:
    break;
  }

  return value;
}

static void
uart_putc(char c)
{
  while((mmio_read8(UART0_BASE + UART_LSR) & UART_LSR_THRE) == 0)
    ;
  mmio_write8(UART0_BASE + UART_THR, (uchar)c);
}

static void
uart_puts(const char *s)
{
  while(*s){
    if(*s == '\n')
      uart_putc('\r');
    uart_putc(*s++);
  }
}

static void
uart_puthex(ulong value)
{
  static const char hex[] = "0123456789abcdef";

  uart_puts("0x");
  for(int i = 60; i >= 0; i -= 4)
    uart_putc(hex[(value >> i) & 0xf]);
}

static void
uart_putkv(const char *key, ulong value)
{
  uart_puts(key);
  uart_puthex(value);
  uart_putc('\n');
}

static void
qemu_poweroff(void)
{
  mmio_write8(SYSCON_BASE, SYSCON_POWEROFF);
  for(;;)
    ;
}

static void
uart_write_buf(const char *buf, ulong len)
{
  for(ulong i = 0; i < len; i++)
    uart_putc(buf[i]);
}

ulong
la_trap_handler(ulong estat, ulong era, ulong badv, ulong badi, ulong *frame)
{
  ulong ecode = (estat >> 16) & 0x3f;
  ulong prmd = csr_read(CSR_PRMD);
  ulong from_plv = prmd & 0x3;

  if(ecode == LA_ECODE_SYS){
    ulong nr = frame[TF_A7];
    ulong a0 = frame[TF_A0];
    ulong a1 = frame[TF_A1];
    ulong a2 = frame[TF_A2];

    if(from_plv == 3 && nr == LA_SYS_WRITE){
      if(a0 == 1 || a0 == 2){
        uart_write_buf((const char *)a1, a2);
        if(a2 == 0 || ((const char *)a1)[a2 - 1] != '\n')
          uart_putc('\n');
        frame[TF_A0] = a2;
      } else {
        frame[TF_A0] = (ulong)-1;
      }
      return era + 4;
    }

    if(from_plv == 3 && nr == LA_SYS_EXIT){
      uart_puts("oscomp-oblivion loongarch64 LA-14 syscall exit dispatch\n");
      uart_putkv("  exit_code=", a0);
      csr_write_prmd(0);
      return (ulong)la_after_user_probe;
    }

    uart_puts("  action=skip syscall instruction and return\n");
    return era + 4;
  }

  uart_puts("oscomp-oblivion loongarch64 trap entered\n");
  uart_putkv("  estat=", estat);
  uart_putkv("  era=", era);
  uart_putkv("  badv=", badv);
  uart_putkv("  badi=", badi);
  uart_putkv("  ecode=", ecode);
  uart_putkv("  from_plv=", from_plv);
  uart_puts("  action=unexpected exception, skip one instruction\n");
  return era + 4;
}

static void
trap_install(void)
{
  /*
   * ECFG.VS=0 selects a single exception entry. Interrupts remain disabled;
   * this LA-2 probe only validates synchronous exception entry and return.
   */
  csr_write_ecfg(0);
  csr_write_eentry((ulong)la_exception_entry);
  uart_putkv("  eentry=", (ulong)la_exception_entry);
  uart_putkv("  crmd_before=", csr_read(CSR_CRMD));
  uart_putkv("  prmd_before=", csr_read(CSR_PRMD));
  uart_putkv("  estat_before=", csr_read(CSR_ESTAT));
  uart_putkv("  era_before=", csr_read(CSR_ERA));
}

static void
trap_probe(void)
{
  uart_puts("oscomp-oblivion loongarch64 LA-2 kernel trap probe\n");
  asm volatile("syscall 0" ::: "memory");
  uart_puts("oscomp-oblivion loongarch64 LA-2 kernel trap returned\n");
}

static void
user_probe(void)
{
  uart_puts("oscomp-oblivion loongarch64 LA-14 enter user public runner\n");
  la_enter_user_probe(la_user_probe, (ulong)(user_stack + sizeof(user_stack)));
}

void
la_user_probe_done(void)
{
  uart_puts("oscomp-oblivion loongarch64 LA-14 user public runner returned to kernel\n");
  qemu_poweroff();
}

void
la_main(void)
{
  uart_puts("oscomp-oblivion loongarch64 LA-14 early serial\n");
  trap_install();
  trap_probe();
  user_probe();
  qemu_poweroff();
}

OUTPUT_ARCH(loongarch)
ENTRY(_start)

SECTIONS
{
  . = 0x9000000000200000;

  .text : ALIGN(4K) {
    *(.text.entry)
    . = ALIGN(4K);
    *(.text.exception)
    *(.text .text.*)
  }

  .rodata : ALIGN(4K) {
    *(.rodata .rodata.*)
  }

  .data : ALIGN(4K) {
    *(.data .data.*)
  }

  .bss : ALIGN(4K) {
    *(.bss.stack)
    *(.bss .bss.* COMMON)
  }
}

