static void
vf2_raw_puts(const char *s)
{
  while (*s)
    sbi_console_putchar(*s++);
}
#endif

volatile static int started = 0;

void
main(unsigned long hartid, unsigned long dtb_pa)
{
#ifdef VISIONFIVE2
  uint64 boot_arg0 = hartid;
  uint64 boot_arg1 = dtb_pa;
  inithartid(0);
#else
  inithartid(hartid);
#endif

#ifdef VISIONFIVE2
  consoleinit();
  printfinit();
  printf("\n[vf2] entered main a0=%p a1=%p\n", boot_arg0, boot_arg1);
  kinit();
  printf("[vf2] kinit done\n");
  kvminit();
  printf("[vf2] kvminit done\n");
  vf2_raw_puts("[vf2] enabling paging\n");
  kvminithart();
  vf2_raw_puts("[vf2] kvminithart returned\n");
  trapinithart();
  vf2_raw_puts("[vf2] trap vector installed (interrupts masked)\n");
  procinit();
  vf2_raw_puts("[vf2] proc table initialized\n");
  timerinit();
  vf2_raw_puts("[vf2] timer state initialized\n");
  vf2_raw_puts("[vf2] enabling STIE only\n");
  set_next_timeout();
  w_sie(SIE_STIE);
  w_sstatus(r_sstatus() | SSTATUS_SIE);
  {
    uint64 deadline = r_time() + INTERVAL * 8;
    while (ticks == 0 && r_time() < deadline)
      asm volatile("" ::: "memory");
  }
  if (ticks != 0)
    vf2_raw_puts("[vf2] timer interrupt observed\n");
  else
    vf2_raw_puts("[vf2] timer interrupt timeout\n");
  vf2_raw_puts("[vf2] early init done; plic/storage/userinit disabled for now\n");
  for (;;)
    asm volatile("wfi");
#else
  if (hartid == 0) {
    consoleinit();
    printfinit();   // init a lock for printf 
    print_logo();
    #ifdef DEBUG
    printf("hart %d enter main()...\n", hartid);
    #endif
    kinit();         // physical page allocator
    kvminit();       // create kernel page table
    kvminithart();   // turn on paging
    timerinit();     // init a lock for timer
    trapinithart();  // install kernel trap vector, including interrupt handler
    procinit();
    plicinit();
    plicinithart();
    #if !defined(QEMU) && !defined(VISIONFIVE2)
    fpioa_pin_init();
    dmac_init();
    #endif 
    disk_init();
    binit();         // buffer cache
    fileinit();      // file table
    userinit();      // first user process
    printf("hart 0 init done\n");

    for(int i = 1; i < NCPU; i++) {
      unsigned long mask = 1 << i;
      sbi_send_ipi(&mask);
    }
    __sync_synchronize();
    started = 1;
  }
  else
  {
    // hart 1
    while (started == 0)
      ;
    __sync_synchronize();
    #ifdef DEBUG
    printf("hart %d enter main()...\n", hartid);
    #endif
    kvminithart();
    trapinithart();
    plicinithart();  // ask PLIC for device interrupts
    printf("hart 1 init done\n");
  }
  scheduler();
#endif
}

